<script lang="ts" setup>
import { Auth, http } from '@/src/http'

const route = useRoute()
const isError = ref(false)

onBeforeMount(async () => {
  try {
    const { plan, email } = route.query

    if (!plan || !email) {
      isError.value = true
      console.error('Proper params not provided')
    }

    await Auth.state.$onLoaded
    Auth.setAccount(`${email}`)
    await nextTick()

    const data = await http.query(route.query).post({}, `/chrome-upgrade`).json<{ url: string }>()
    location.href = data.url
  }

  catch (error) {
    console.error(error)
    isError.value = true
  }
})
</script>

<template>
  <div class="gap-4 flex-col-center size-full">
    <Spinner class="text-primary" />

    <span>
      <template v-if="isError">
        An error occurred. Please contact us
      </template>

      <template v-else>
        Authorizing for <b>{{ $route.query.email }}</b>
      </template>
    </span>
  </div>
</template>

<route lang="yaml">
meta:
  auth: false
</route>
